package handlers

import (
	"crypto/rand"
	"database/sql"
	"encoding/hex"
	"encoding/json"
	"fmt"
	"log"
	"net/http"
	"strings"
	"time"

	"compliance-console/internal/middleware"
	"compliance-console/internal/models"
	"compliance-console/internal/services"

	"github.com/google/uuid"
	"github.com/labstack/echo/v4"
	"golang.org/x/crypto/argon2"
)

// AuthHandler contains dependencies for authentication endpoints.
type AuthHandler struct {
	DB *sql.DB
	AL *services.AuditLedger
}

// NewAuthHandler creates a new AuthHandler.
func NewAuthHandler(db *sql.DB) *AuthHandler {
	return &AuthHandler{DB: db, AL: services.NewAuditLedger(db)}
}

// Login authenticates a user and creates a session.
func (h *AuthHandler) Login(c echo.Context) error {
	var req models.LoginRequest
	if err := c.Bind(&req); err != nil {
		return c.JSON(http.StatusBadRequest, map[string]string{
			"error": "Invalid request body",
		})
	}

	if len(req.Password) < 12 {
		return c.JSON(http.StatusBadRequest, map[string]string{
			"error": "Password must be at least 12 characters",
		})
	}

	// Check account lock
	if err := middleware.CheckAccountLock(h.DB, req.Username); err != nil {
		return c.JSON(http.StatusForbidden, map[string]string{
			"error": err.Error(),
		})
	}

	// Fetch user
	var user models.User
	var roleName string
	err := h.DB.QueryRow(`
		SELECT u.id, u.tenant_id, u.role_id, u.username, u.email, u.full_name,
		       u.password_hash, u.failed_login_attempts, u.locked_until,
		       u.captcha_required, u.last_login_at, u.created_at, u.updated_at,
		       u.is_active, r.name
		FROM users u
		JOIN roles r ON u.role_id = r.id
		WHERE u.username = $1
	`, req.Username).Scan(
		&user.ID, &user.TenantID, &user.RoleID, &user.Username, &user.Email, &user.FullName,
		&user.PasswordHash, &user.FailedLoginAttempts, &user.LockedUntil,
		&user.CaptchaRequired, &user.LastLoginAt, &user.CreatedAt, &user.UpdatedAt,
		&user.IsActive, &roleName,
	)
	if err == sql.ErrNoRows {
		return c.JSON(http.StatusUnauthorized, map[string]string{
			"error": "Invalid credentials",
		})
	}
	if err != nil {
		return c.JSON(http.StatusInternalServerError, map[string]string{
			"error": "Internal server error",
		})
	}

	if !user.IsActive {
		return c.JSON(http.StatusForbidden, map[string]string{
			"error": "Account is deactivated",
		})
	}

	// Verify password using Argon2
	if !verifyArgon2Hash(req.Password, user.PasswordHash) {
		middleware.TrackFailedLogin(h.DB, req.Username)
		return c.JSON(http.StatusUnauthorized, map[string]string{
			"error": "Invalid credentials",
		})
	}

	// Reset failed login attempts on success
	middleware.ResetLoginAttempts(h.DB, req.Username)

	// Generate session token
	tokenBytes := make([]byte, 32)
	if _, err := rand.Read(tokenBytes); err != nil {
		return c.JSON(http.StatusInternalServerError, map[string]string{
			"error": "Failed to generate session token",
		})
	}
	token := hex.EncodeToString(tokenBytes)

	sessionID := uuid.New()
	expiresAt := time.Now().Add(middleware.SessionIdleTimeout)

	_, err = h.DB.Exec(`
		INSERT INTO sessions (id, user_id, token, expires_at)
		VALUES ($1, $2, $3, $4)
	`, sessionID, user.ID, token, expiresAt)
	if err != nil {
		return c.JSON(http.StatusInternalServerError, map[string]string{
			"error": "Failed to create session",
		})
	}

	// Set session cookie
	c.SetCookie(&http.Cookie{
		Name:     middleware.SessionCookieName,
		Value:    token,
		Path:     "/",
		HttpOnly: true,
		Secure:   true,
		SameSite: http.SameSiteStrictMode,
		MaxAge:   int(middleware.SessionIdleTimeout.Seconds()),
	})

	user.RoleName = roleName

	// Audit log — critical action, route through immutable ledger (fail-closed)
	if err := writeCriticalAuditLog(h.AL, h.DB, &user.TenantID, &user.ID, "login", "user", &user.ID, nil, c.RealIP()); err != nil {
		return c.JSON(http.StatusInternalServerError, map[string]string{
			"error": "Audit system unavailable, login denied",
		})
	}

	return c.JSON(http.StatusOK, models.LoginResponse{
		User: user,
	})
}

// Logout destroys the current session.
func (h *AuthHandler) Logout(c echo.Context) error {
	user := middleware.GetUserFromContext(c)

	session, ok := c.Get("session").(*models.Session)
	if ok && session != nil {
		_, _ = h.DB.Exec("DELETE FROM sessions WHERE id = $1", session.ID)
	}

	// Clear cookie
	c.SetCookie(&http.Cookie{
		Name:     middleware.SessionCookieName,
		Value:    "",
		Path:     "/",
		HttpOnly: true,
		Secure:   true,
		SameSite: http.SameSiteStrictMode,
		MaxAge:   -1,
	})

	if user != nil {
		if err := writeCriticalAuditLog(h.AL, h.DB, &user.TenantID, &user.ID, "logout", "user", &user.ID, nil, c.RealIP()); err != nil {
			return c.JSON(http.StatusInternalServerError, map[string]string{
				"error": "Audit system unavailable, logout denied",
			})
		}
	}

	return c.JSON(http.StatusOK, map[string]string{
		"message": "Logged out successfully",
	})
}

// GetSession returns the current authenticated user's info.
func (h *AuthHandler) GetSession(c echo.Context) error {
	user := middleware.GetUserFromContext(c)
	if user == nil {
		return c.JSON(http.StatusUnauthorized, map[string]string{
			"error": "Not authenticated",
		})
	}

	return c.JSON(http.StatusOK, map[string]interface{}{
		"user": user,
	})
}

// verifyArgon2Hash checks a password against an Argon2id hash string.
func verifyArgon2Hash(password, encodedHash string) bool {
	parts := strings.Split(encodedHash, "$")
	// Expected format: ["", "argon2id", "v=19", "m=65536,t=3,p=4", "<salt>", "<hash>"]
	if len(parts) != 6 {
		return false
	}

	var memory uint32
	var iterations uint32
	var parallelism uint8
	_, err := fmt.Sscanf(parts[3], "m=%d,t=%d,p=%d", &memory, &iterations, &parallelism)
	if err != nil {
		return false
	}

	salt, err := hex.DecodeString(parts[4])
	if err != nil {
		// Try using raw bytes as salt (for base64 or plain text salts)
		salt = []byte(parts[4])
	}

	expectedHash, err := hex.DecodeString(parts[5])
	if err != nil {
		// Try using raw bytes
		expectedHash = []byte(parts[5])
	}

	keyLen := uint32(len(expectedHash))
	if keyLen == 0 {
		keyLen = 32
	}

	derivedKey := argon2.IDKey([]byte(password), salt, iterations, memory, parallelism, keyLen)

	return constantTimeCompare(derivedKey, expectedHash)
}

// constantTimeCompare performs a constant-time byte comparison.
func constantTimeCompare(a, b []byte) bool {
	if len(a) != len(b) {
		return false
	}
	var result byte
	for i := range a {
		result |= a[i] ^ b[i]
	}
	return result == 0
}

// HashPasswordArgon2 creates an Argon2id hash of the password.
func HashPasswordArgon2(password string) (string, error) {
	salt := make([]byte, 16)
	if _, err := rand.Read(salt); err != nil {
		return "", err
	}

	key := argon2.IDKey([]byte(password), salt, 3, 64*1024, 4, 32)

	hash := fmt.Sprintf("$argon2id$v=%d$m=%d,t=%d,p=%d$%s$%s",
		argon2.Version, 64*1024, 3, 4,
		hex.EncodeToString(salt),
		hex.EncodeToString(key),
	)

	return hash, nil
}

// writeAuditLog is a helper to insert an audit log entry.
func writeAuditLog(db *sql.DB, tenantID *uuid.UUID, userID *uuid.UUID, action, resourceType string, resourceID *uuid.UUID, details *string, ipAddress string) {
	id := uuid.New()
	_, _ = db.Exec(`
		INSERT INTO audit_logs (id, tenant_id, user_id, action, resource_type, resource_id, details, ip_address)
		VALUES ($1, $2, $3, $4, $5, $6, $7, $8::inet)
	`, id, tenantID, userID, action, resourceType, resourceID, details, ipAddress)
}

// criticalActions defines actions that must be routed through the immutable audit ledger.
var criticalActions = map[string]bool{
	"login": true, "logout": true, "login_failed": true,
	"create_user": true, "deactivate_user": true, "update_user_role": true,
	"review_decision": true, "promote_content": true, "rollback_content": true,
	"create_schedule": true, "cancel_schedule": true, "confirm_assignment": true,
	"reassign_schedule": true,
	"store_sensitive_data": true, "reveal_sensitive_data": true, "rotate_encryption_key": true,
	"resolve_exception": true, "assign_exception": true,
}

// writeCriticalAuditLog routes critical actions to the immutable audit_ledger and also writes to audit_logs.
// Returns an error if the immutable ledger append fails — callers MUST treat this as a hard failure
// to preserve compliance traceability guarantees (fail-closed).
func writeCriticalAuditLog(al *services.AuditLedger, db *sql.DB, tenantID *uuid.UUID, userID *uuid.UUID, action, resourceType string, resourceID *uuid.UUID, details *string, ipAddress string) error {
	// Write to immutable audit_ledger first — if this fails, the action must not proceed
	resID := ""
	if resourceID != nil {
		resID = resourceID.String()
	}
	var detailsMap map[string]interface{}
	if details != nil && *details != "" {
		_ = json.Unmarshal([]byte(*details), &detailsMap)
	}
	if err := al.Append(tenantID, userID, action, resourceType, resID, detailsMap, ipAddress); err != nil {
		log.Printf("CRITICAL: immutable audit ledger append failed for action=%s: %v", action, err)
		return fmt.Errorf("immutable audit log write failed: %w", err)
	}

	// Also write to mutable audit_logs for general querying
	writeAuditLog(db, tenantID, userID, action, resourceType, resourceID, details, ipAddress)
	return nil
}

package middleware

import (
	"bytes"
	"database/sql"
	"encoding/json"
	"fmt"
	"io"
	"math/rand"
	"net/http"
	"strconv"
	"time"

	"compliance-console/internal/models"

	"github.com/google/uuid"
	"github.com/labstack/echo/v4"
)

const (
	SessionCookieName = "session_token"
	SessionIdleTimeout = 30 * time.Minute
)

// AuthMiddleware validates session tokens and refreshes idle timeout.
func AuthMiddleware(db *sql.DB) echo.MiddlewareFunc {
	return func(next echo.HandlerFunc) echo.HandlerFunc {
		return func(c echo.Context) error {
			cookie, err := c.Cookie(SessionCookieName)
			if err != nil || cookie.Value == "" {
				return c.JSON(http.StatusUnauthorized, map[string]string{
					"error": "Authentication required",
				})
			}

			token := cookie.Value

			var session models.Session
			var user models.User
			var roleName string
			err = db.QueryRow(`
				SELECT s.id, s.user_id, s.token, s.expires_at, s.created_at,
				       u.id, u.tenant_id, u.role_id, u.username, u.email, u.full_name,
				       u.failed_login_attempts, u.locked_until, u.captcha_required,
				       u.last_login_at, u.created_at, u.updated_at, u.is_active,
				       u.location_id,
				       r.name
				FROM sessions s
				JOIN users u ON s.user_id = u.id
				JOIN roles r ON u.role_id = r.id
				WHERE s.token = $1
			`, token).Scan(
				&session.ID, &session.UserID, &session.Token, &session.ExpiresAt, &session.CreatedAt,
				&user.ID, &user.TenantID, &user.RoleID, &user.Username, &user.Email, &user.FullName,
				&user.FailedLoginAttempts, &user.LockedUntil, &user.CaptchaRequired,
				&user.LastLoginAt, &user.CreatedAt, &user.UpdatedAt, &user.IsActive,
				&user.LocationID,
				&roleName,
			)
			if err == sql.ErrNoRows {
				return c.JSON(http.StatusUnauthorized, map[string]string{
					"error": "Invalid or expired session",
				})
			}
			if err != nil {
				return c.JSON(http.StatusInternalServerError, map[string]string{
					"error": "Failed to validate session",
				})
			}

			if time.Now().After(session.ExpiresAt) {
				// Clean up expired session
				_, _ = db.Exec("DELETE FROM sessions WHERE id = $1", session.ID)
				return c.JSON(http.StatusUnauthorized, map[string]string{
					"error": "Session expired",
				})
			}

			if !user.IsActive {
				return c.JSON(http.StatusForbidden, map[string]string{
					"error": "Account is deactivated",
				})
			}

			// Refresh idle timeout
			newExpiry := time.Now().Add(SessionIdleTimeout)
			_, _ = db.Exec("UPDATE sessions SET expires_at = $1 WHERE id = $2", newExpiry, session.ID)

			user.RoleName = roleName

			// Store user info in context
			c.Set("user", &user)
			c.Set("session", &session)
			c.Set("tenant_id", user.TenantID)

			return next(c)
		}
	}
}

// RoleGuard returns middleware that restricts access to specified roles.
func RoleGuard(allowedRoles ...string) echo.MiddlewareFunc {
	return func(next echo.HandlerFunc) echo.HandlerFunc {
		return func(c echo.Context) error {
			user, ok := c.Get("user").(*models.User)
			if !ok || user == nil {
				return c.JSON(http.StatusUnauthorized, map[string]string{
					"error": "Authentication required",
				})
			}

			for _, role := range allowedRoles {
				if user.RoleName == role {
					return next(c)
				}
			}

			return c.JSON(http.StatusForbidden, map[string]string{
				"error": "Insufficient permissions",
			})
		}
	}
}

// CaptchaCheck is a placeholder middleware that checks the captcha_required flag.
func CaptchaCheck(db *sql.DB) echo.MiddlewareFunc {
	return func(next echo.HandlerFunc) echo.HandlerFunc {
		return func(c echo.Context) error {
			// This is a placeholder for CAPTCHA verification.
			// In a real implementation, this would validate a CAPTCHA token
			// from the request against a CAPTCHA service.

			var req models.LoginRequest
			// Only applicable to login requests
			if c.Request().URL.Path != "/api/auth/login" {
				return next(c)
			}

			// Peek at the username to check if captcha is required
			body, readErr := io.ReadAll(c.Request().Body)
			if readErr != nil {
				return next(c)
			}
			// Reset body for downstream handler
			c.Request().Body = io.NopCloser(bytes.NewReader(body))
			if err := json.Unmarshal(body, &req); err != nil {
				return next(c)
			}

			var captchaRequired bool
			err := db.QueryRow(
				"SELECT captcha_required FROM users WHERE username = $1",
				req.Username,
			).Scan(&captchaRequired)
			if err != nil {
				// User not found, let the login handler deal with it
				return next(c)
			}

			if captchaRequired {
				captchaToken := c.Request().Header.Get("X-Captcha-Token")
				if captchaToken == "" {
					// Generate a random math challenge
					a := rand.Intn(20) + 1
					b := rand.Intn(20) + 1
					answer := a + b
					// Store the answer in the database
					_, _ = db.Exec(
						"UPDATE users SET captcha_answer = $1, updated_at = NOW() WHERE username = $2",
						answer, req.Username,
					)
					return c.JSON(http.StatusBadRequest, map[string]string{
						"error":             "CAPTCHA verification required",
						"captcha_required":  "true",
						"captcha_challenge": fmt.Sprintf("What is %d + %d?", a, b),
					})
				}
				// Validate the CAPTCHA answer
				userAnswer, parseErr := strconv.Atoi(captchaToken)
				if parseErr != nil {
					// Generate a new challenge on bad input
					a := rand.Intn(20) + 1
					b := rand.Intn(20) + 1
					answer := a + b
					_, _ = db.Exec(
						"UPDATE users SET captcha_answer = $1, updated_at = NOW() WHERE username = $2",
						answer, req.Username,
					)
					return c.JSON(http.StatusBadRequest, map[string]string{
						"error":             "Invalid CAPTCHA answer",
						"captcha_required":  "true",
						"captcha_challenge": fmt.Sprintf("What is %d + %d?", a, b),
					})
				}
				var storedAnswer int
				err = db.QueryRow(
					"SELECT captcha_answer FROM users WHERE username = $1",
					req.Username,
				).Scan(&storedAnswer)
				if err != nil || userAnswer != storedAnswer {
					// Wrong answer — generate a new challenge
					a := rand.Intn(20) + 1
					b := rand.Intn(20) + 1
					newAnswer := a + b
					_, _ = db.Exec(
						"UPDATE users SET captcha_answer = $1, updated_at = NOW() WHERE username = $2",
						newAnswer, req.Username,
					)
					return c.JSON(http.StatusBadRequest, map[string]string{
						"error":             "Incorrect CAPTCHA answer",
						"captcha_required":  "true",
						"captcha_challenge": fmt.Sprintf("What is %d + %d?", a, b),
					})
				}
			}

			return next(c)
		}
	}
}

// GetUserFromContext extracts the authenticated user from the echo context.
func GetUserFromContext(c echo.Context) *models.User {
	user, ok := c.Get("user").(*models.User)
	if !ok {
		return nil
	}
	return user
}

// GetTenantIDFromContext extracts the tenant ID from the echo context.
func GetTenantIDFromContext(c echo.Context) uuid.UUID {
	tenantID, ok := c.Get("tenant_id").(uuid.UUID)
	if !ok {
		return uuid.Nil
	}
	return tenantID
}

package middleware

import (
	"database/sql"
	"fmt"
	"net/http"
	"strconv"
	"time"

	"compliance-console/internal/models"

	"github.com/labstack/echo/v4"
)

// RateLimiter returns Echo middleware that enforces rate limits using a
// sliding-window approach backed by the rate_limits table.
func RateLimiter(db *sql.DB, maxRequests int, windowMinutes int) echo.MiddlewareFunc {
	return func(next echo.HandlerFunc) echo.HandlerFunc {
		return func(c echo.Context) error {
			now := time.Now().UTC()
			windowStart := now.Truncate(time.Duration(windowMinutes) * time.Minute)
			windowEnd := windowStart.Add(time.Duration(windowMinutes) * time.Minute)

			// Determine identifiers
			var userIdentifier string
			user := GetUserFromContext(c)
			if user != nil {
				userIdentifier = user.ID.String()
			}
			ipIdentifier := c.RealIP()

			// Check and increment user-based rate limit
			if userIdentifier != "" {
				remaining, err := checkAndIncrement(db, userIdentifier, "user", windowStart, maxRequests)
				if err != nil {
					return c.JSON(http.StatusInternalServerError, map[string]string{
						"error": "Rate limit check failed",
					})
				}
				if remaining < 0 {
					retryAfter := int(time.Until(windowEnd).Seconds())
					if retryAfter < 1 {
						retryAfter = 1
					}
					c.Response().Header().Set("Retry-After", strconv.Itoa(retryAfter))
					c.Response().Header().Set("X-RateLimit-Limit", strconv.Itoa(maxRequests))
					c.Response().Header().Set("X-RateLimit-Remaining", "0")
					c.Response().Header().Set("X-RateLimit-Reset", strconv.FormatInt(windowEnd.Unix(), 10))
					return c.JSON(http.StatusTooManyRequests, map[string]string{
						"error": "Rate limit exceeded",
					})
				}

				c.Response().Header().Set("X-RateLimit-Limit", strconv.Itoa(maxRequests))
				c.Response().Header().Set("X-RateLimit-Remaining", strconv.Itoa(remaining))
				c.Response().Header().Set("X-RateLimit-Reset", strconv.FormatInt(windowEnd.Unix(), 10))
			}

			// Check and increment IP-based rate limit
			remaining, err := checkAndIncrement(db, ipIdentifier, "ip", windowStart, maxRequests)
			if err != nil {
				return c.JSON(http.StatusInternalServerError, map[string]string{
					"error": "Rate limit check failed",
				})
			}
			if remaining < 0 {
				retryAfter := int(time.Until(windowEnd).Seconds())
				if retryAfter < 1 {
					retryAfter = 1
				}
				c.Response().Header().Set("Retry-After", strconv.Itoa(retryAfter))
				c.Response().Header().Set("X-RateLimit-Limit", strconv.Itoa(maxRequests))
				c.Response().Header().Set("X-RateLimit-Remaining", "0")
				c.Response().Header().Set("X-RateLimit-Reset", strconv.FormatInt(windowEnd.Unix(), 10))
				return c.JSON(http.StatusTooManyRequests, map[string]string{
					"error": "Rate limit exceeded",
				})
			}

			// Set headers if not already set by user-based check
			if userIdentifier == "" {
				c.Response().Header().Set("X-RateLimit-Limit", strconv.Itoa(maxRequests))
				c.Response().Header().Set("X-RateLimit-Remaining", strconv.Itoa(remaining))
				c.Response().Header().Set("X-RateLimit-Reset", strconv.FormatInt(windowEnd.Unix(), 10))
			}

			return next(c)
		}
	}
}

// checkAndIncrement checks the current request count for an identifier in the
// given window and increments it. Returns the remaining requests, or a negative
// value if the limit has been exceeded.
func checkAndIncrement(db *sql.DB, identifier, identifierType string, windowStart time.Time, maxRequests int) (int, error) {
	var count int
	err := db.QueryRow(`
		INSERT INTO rate_limits (identifier, identifier_type, window_start, request_count)
		VALUES ($1, $2, $3, 1)
		ON CONFLICT (identifier, identifier_type, window_start)
		DO UPDATE SET request_count = rate_limits.request_count + 1
		RETURNING request_count
	`, identifier, identifierType, windowStart).Scan(&count)
	if err != nil {
		return 0, fmt.Errorf("failed to upsert rate limit: %w", err)
	}

	remaining := maxRequests - count
	return remaining, nil
}

// CleanupOldWindows deletes rate_limits entries older than 5 minutes.
func CleanupOldWindows(db *sql.DB) error {
	cutoff := time.Now().UTC().Add(-5 * time.Minute)
	_, err := db.Exec(`DELETE FROM rate_limits WHERE window_start < $1`, cutoff)
	if err != nil {
		return fmt.Errorf("failed to cleanup old rate limit windows: %w", err)
	}
	return nil
}

// GetRateLimitStatus returns the current rate limit status for a given identifier.
func GetRateLimitStatus(db *sql.DB, identifier, identifierType string, maxRequests, windowMinutes int) (*models.RateLimitStatus, error) {
	now := time.Now().UTC()
	windowStart := now.Truncate(time.Duration(windowMinutes) * time.Minute)
	windowEnd := windowStart.Add(time.Duration(windowMinutes) * time.Minute)

	var count int
	err := db.QueryRow(`
		SELECT COALESCE(request_count, 0) FROM rate_limits
		WHERE identifier = $1 AND identifier_type = $2 AND window_start = $3
	`, identifier, identifierType, windowStart).Scan(&count)
	if err == sql.ErrNoRows {
		count = 0
	} else if err != nil {
		return nil, fmt.Errorf("failed to get rate limit status: %w", err)
	}

	remaining := maxRequests - count
	if remaining < 0 {
		remaining = 0
	}

	return &models.RateLimitStatus{
		Identifier:        identifier,
		Type:              identifierType,
		RequestsRemaining: remaining,
		WindowReset:       windowEnd,
	}, nil
}

package middleware

import (
	"database/sql"
	"fmt"
	"time"
)

const (
	MaxFailedAttempts       = 5
	CaptchaThreshold        = 3
	LockDuration            = 30 * time.Minute
	FailedAttemptWindow     = 15 * time.Minute
)

// CheckAccountLock verifies whether the user account is currently locked.
// Returns an error message if the account is locked, nil otherwise.
func CheckAccountLock(db *sql.DB, username string) error {
	var lockedUntil *time.Time
	err := db.QueryRow(
		"SELECT locked_until FROM users WHERE username = $1",
		username,
	).Scan(&lockedUntil)
	if err != nil {
		if err == sql.ErrNoRows {
			return nil // User not found; let the login handler deal with it
		}
		return fmt.Errorf("failed to check account lock status")
	}

	if lockedUntil != nil && time.Now().Before(*lockedUntil) {
		remaining := time.Until(*lockedUntil).Round(time.Minute)
		return fmt.Errorf("account is locked, try again in %v", remaining)
	}

	// If lock has expired, clear it
	if lockedUntil != nil {
		_, _ = db.Exec(`
			UPDATE users
			SET locked_until = NULL, failed_login_attempts = 0, captcha_required = FALSE, updated_at = NOW()
			WHERE username = $1
		`, username)
	}

	return nil
}

// TrackFailedLogin increments the failed login counter and applies
// progressive security measures (CAPTCHA requirement, account lock).
func TrackFailedLogin(db *sql.DB, username string) {
	// Check if the last failure was within the rolling window
	var lastFailedAt *time.Time
	var failedAttempts int
	_ = db.QueryRow(
		"SELECT last_failed_at, failed_login_attempts FROM users WHERE username = $1",
		username,
	).Scan(&lastFailedAt, &failedAttempts)

	// If outside the 15-minute window, reset the counter
	if lastFailedAt == nil || time.Since(*lastFailedAt) > FailedAttemptWindow {
		_, _ = db.Exec(`
			UPDATE users
			SET failed_login_attempts = 1,
			    last_failed_at = NOW(),
			    updated_at = NOW()
			WHERE username = $1
		`, username)
		failedAttempts = 1
	} else {
		// Within window — increment
		_, _ = db.Exec(`
			UPDATE users
			SET failed_login_attempts = failed_login_attempts + 1,
			    last_failed_at = NOW(),
			    updated_at = NOW()
			WHERE username = $1
		`, username)
		failedAttempts++
	}

	// Require CAPTCHA after 3 failed attempts in window
	if failedAttempts >= CaptchaThreshold {
		_, _ = db.Exec(`
			UPDATE users SET captcha_required = TRUE, updated_at = NOW()
			WHERE username = $1
		`, username)
	}

	// Lock account after 5 failed attempts in window
	if failedAttempts >= MaxFailedAttempts {
		lockUntil := time.Now().Add(LockDuration)
		_, _ = db.Exec(`
			UPDATE users SET locked_until = $1, updated_at = NOW()
			WHERE username = $2
		`, lockUntil, username)
	}
}

// ResetLoginAttempts clears the failed login counter and related flags
// after a successful login.
func ResetLoginAttempts(db *sql.DB, username string) {
	_, _ = db.Exec(`
		UPDATE users
		SET failed_login_attempts = 0,
		    locked_until = NULL,
		    captcha_required = FALSE,
		    last_login_at = NOW(),
		    updated_at = NOW()
		WHERE username = $1
	`, username)
}

