122	// decryptDEK retrieves and decrypts the data-encryption key (DEK) for a given alias and tenant.
123	// Returns the raw 32-byte DEK or an error.
124	func (s *EncryptionService) decryptDEK(db *sql.DB, tenantID uuid.UUID, keyAlias string) ([]byte, error) {
125		var encryptedKey, nonce []byte
126		err := db.QueryRow(`
127			SELECT encrypted_key, nonce FROM encryption_keys
128			WHERE key_alias = $1 AND tenant_id = $2 AND status = 'active'
129		`, keyAlias, tenantID).Scan(&encryptedKey, &nonce)
130		if err != nil {
131			return nil, fmt.Errorf("failed to retrieve DEK for alias %s: %w", keyAlias, err)
132		}
133	
134		// If nonce is nil, the key was bootstrapped before envelope encryption was added.
135		// Cannot decrypt the DEK without its nonce — caller should fall back to master key.
136		if nonce == nil {
137			return nil, fmt.Errorf("DEK for alias %s has no nonce (legacy key without envelope encryption)", keyAlias)
138		}
139	
140		dek, err := s.Decrypt(encryptedKey, nonce)
141		if err != nil {
142			return nil, fmt.Errorf("failed to decrypt DEK for alias %s: %w", keyAlias, err)
143		}
144		return dek, nil
145	}
146	
147	// encryptWithKey encrypts plaintext using a specific key (not the master key).
148	func encryptWithKey(key, plaintext []byte) (ciphertext []byte, nonce []byte, err error) {
149		block, err := aes.NewCipher(key)
150		if err != nil {
151			return nil, nil, fmt.Errorf("failed to create cipher: %w", err)
152		}
153		gcm, err := cipher.NewGCM(block)
154		if err != nil {
155			return nil, nil, fmt.Errorf("failed to create GCM: %w", err)
156		}
157		nonce = make([]byte, gcm.NonceSize())
158		if _, err := io.ReadFull(rand.Reader, nonce); err != nil {
159			return nil, nil, fmt.Errorf("failed to generate nonce: %w", err)
160		}
161		ciphertext = gcm.Seal(nil, nonce, plaintext, nil)
162		return ciphertext, nonce, nil
163	}
164	
165	// decryptWithKey decrypts ciphertext using a specific key (not the master key).
166	func decryptWithKey(key, ciphertext, nonce []byte) ([]byte, error) {
167		block, err := aes.NewCipher(key)
168		if err != nil {
169			return nil, fmt.Errorf("failed to create cipher: %w", err)
170		}
171		gcm, err := cipher.NewGCM(block)
172		if err != nil {
173			return nil, fmt.Errorf("failed to create GCM: %w", err)
174		}
175		plaintext, err := gcm.Open(nil, nonce, ciphertext, nil)
176		if err != nil {
177			return nil, fmt.Errorf("failed to decrypt: %w", err)
178		}
179		return plaintext, nil
180	}
181	
182	// DecryptValue decrypts ciphertext using the DEK identified by keyAlias (envelope decryption).
183	// Falls back to master key if no DEK is registered for backward compatibility.
184	func (s *EncryptionService) DecryptValue(db *sql.DB, tenantID uuid.UUID, keyAlias string, ciphertext, nonce []byte) ([]byte, error) {
185		dek, dekErr := s.decryptDEK(db, tenantID, keyAlias)
186		if dekErr != nil {
187			// Fallback to master key for backward compatibility
188			return s.Decrypt(ciphertext, nonce)
189		}
190		return decryptWithKey(dek, ciphertext, nonce)
191	}
192	
193	// StoreSensitiveField encrypts and stores a sensitive value in the sensitive_data table.
194	// Uses envelope encryption: retrieves the DEK by alias, encrypts data with the DEK.
195	// Falls back to master key if no DEK is registered (backward compatibility).
196	func (s *EncryptionService) StoreSensitiveField(db *sql.DB, tenantID, ownerID uuid.UUID, dataType, value, label, keyAlias string) error {
197		var ciphertext, nonce []byte
198		var err error
199	
200		dek, dekErr := s.decryptDEK(db, tenantID, keyAlias)
201		if dekErr != nil {
202			// Fallback to master key for backward compatibility (no DEK registered yet)
203			ciphertext, nonce, err = s.Encrypt([]byte(value))
204		} else {
205			ciphertext, nonce, err = encryptWithKey(dek, []byte(value))
206		}
207		if err != nil {
208			return fmt.Errorf("encryption failed: %w", err)
209		}
210	
211		_, err = db.Exec(`
212			INSERT INTO sensitive_data (tenant_id, owner_id, data_type, encrypted_value, nonce, key_alias, label)
213			VALUES ($1, $2, $3, $4, $5, $6, $7)
214		`, tenantID, ownerID, dataType, ciphertext, nonce, keyAlias, label)
215		if err != nil {
216			return fmt.Errorf("failed to store sensitive data: %w", err)
217		}
218	
219		return nil
220	}
221	
222	// RetrieveSensitiveField decrypts and returns the plaintext value for a sensitive_data record.
223	// Uses envelope decryption: retrieves the DEK by alias, decrypts data with the DEK.
224	// Falls back to master key if no DEK is registered (backward compatibility).
225	func (s *EncryptionService) RetrieveSensitiveField(db *sql.DB, id uuid.UUID, tenantID uuid.UUID) (string, error) {
226		var encryptedValue, nonce []byte
227		var keyAlias string
228		err := db.QueryRow(`
229			SELECT encrypted_value, nonce, key_alias FROM sensitive_data WHERE id = $1 AND tenant_id = $2
230		`, id, tenantID).Scan(&encryptedValue, &nonce, &keyAlias)
231		if err != nil {
232			return "", fmt.Errorf("failed to retrieve sensitive data: %w", err)
233		}
234	
235		// Try envelope decryption with DEK first
236		dek, dekErr := s.decryptDEK(db, tenantID, keyAlias)
237		var plaintext []byte
238		if dekErr != nil {
239			// Fallback: try master key directly (data encrypted before envelope encryption was enabled)
240			plaintext, err = s.Decrypt(encryptedValue, nonce)
241		} else {
242			plaintext, err = decryptWithKey(dek, encryptedValue, nonce)
243		}
244		if err != nil {
245			return "", fmt.Errorf("decryption failed: %w", err)
246		}
247	
248		return string(plaintext), nil
249	}
250	
251	// MaskValue returns a masked version of the value showing only the last 4 characters.
252	// For values shorter than 4 characters, the entire value is masked.
253	func (s *EncryptionService) MaskValue(value string) string {
254		if len(value) <= 4 {
255			return "****"
256		}
257		return "****" + value[len(value)-4:]
258	}
259	
260	// RotateKey creates a new data-encryption key (DEK) and re-encrypts all sensitive_data rows
261	// that use the old key alias with the new DEK. The DEK is itself encrypted with the master key
262	// (envelope encryption) and stored alongside its nonce.
263	func (s *EncryptionService) RotateKey(db *sql.DB, tenantID uuid.UUID, oldAlias, newAlias string) error {
264		tx, err := db.Begin()
265		if err != nil {
266			return fmt.Errorf("failed to begin transaction: %w", err)
267		}
268		defer tx.Rollback()
269	
270		// Generate a new DEK
271		newDEK, err := s.GenerateKey()
272		if err != nil {
273			return fmt.Errorf("failed to generate new key: %w", err)
274		}
275	
276		// Encrypt the new DEK with the master key for storage (envelope encryption)
277		encNewKey, encNonce, err := s.Encrypt(newDEK)
278		if err != nil {
279			return fmt.Errorf("failed to encrypt new key: %w", err)
280		}
281	
282		// Retrieve and decrypt the old DEK to re-encrypt data
283		var oldEncKey, oldNonce []byte
284		err = tx.QueryRow(`
285			SELECT encrypted_key, nonce FROM encryption_keys WHERE key_alias = $1 AND tenant_id = $2
286		`, oldAlias, tenantID).Scan(&oldEncKey, &oldNonce)
287		if err != nil {
288			return fmt.Errorf("failed to retrieve old key: %w", err)
289		}
290	
291		var oldDEK []byte
292		if oldNonce != nil {
293			// Old key was stored with envelope encryption — decrypt with master key
294			oldDEK, err = s.Decrypt(oldEncKey, oldNonce)
295			if err != nil {
296				return fmt.Errorf("failed to decrypt old DEK: %w", err)
297			}
298		}
299	
300		// Get the old key's rotation number
301		var rotationNumber int
302		err = tx.QueryRow(`SELECT rotation_number FROM encryption_keys WHERE key_alias = $1 AND tenant_id = $2`, oldAlias, tenantID).Scan(&rotationNumber)
303		if err != nil {
304			return fmt.Errorf("failed to get old key rotation number: %w", err)
305		}
306	
307		// Insert new key entry with both encrypted key and its nonce
308		_, err = tx.Exec(`
309			INSERT INTO encryption_keys (tenant_id, key_alias, encrypted_key, nonce, algorithm, status, rotation_number, activated_at)
310			VALUES ($1, $2, $3, $4, 'AES-256-GCM', 'active', $5, NOW())
311		`, tenantID, newAlias, encNewKey, encNonce, rotationNumber+1)
312		if err != nil {
313			return fmt.Errorf("failed to insert new key: %w", err)
314		}
315	
316		// Re-encrypt all sensitive_data rows using the old alias for this tenant
317		rows, err := tx.Query(`
318			SELECT id, encrypted_value, nonce FROM sensitive_data WHERE key_alias = $1 AND tenant_id = $2
319		`, oldAlias, tenantID)
320		if err != nil {
321			return fmt.Errorf("failed to query sensitive data for re-encryption: %w", err)
322		}
323		defer rows.Close()
324	
325		type reEncryptRow struct {
326			id         uuid.UUID
327			ciphertext []byte
328			nonce      []byte
329		}
330	
331		var toUpdate []reEncryptRow
332		for rows.Next() {
333			var r reEncryptRow
334			if err := rows.Scan(&r.id, &r.ciphertext, &r.nonce); err != nil {
335				return fmt.Errorf("failed to scan row: %w", err)
336			}
337			toUpdate = append(toUpdate, r)
338		}
339		rows.Close()
340	
341		for _, r := range toUpdate {
342			// Decrypt with old DEK (or master key for legacy data)
343			var plaintext []byte
344			if oldDEK != nil {
345				plaintext, err = decryptWithKey(oldDEK, r.ciphertext, r.nonce)
346			} else {
347				plaintext, err = s.Decrypt(r.ciphertext, r.nonce)
348			}
349			if err != nil {
350				return fmt.Errorf("failed to decrypt row %s: %w", r.id, err)
351			}
352	
353			// Re-encrypt with the new DEK
354			newCiphertext, newNonce, err := encryptWithKey(newDEK, plaintext)
355			if err != nil {
356				return fmt.Errorf("failed to re-encrypt row %s: %w", r.id, err)
357			}
358	
359			_, err = tx.Exec(`
360				UPDATE sensitive_data SET encrypted_value = $1, nonce = $2, key_alias = $3, updated_at = NOW()
361				WHERE id = $4 AND tenant_id = $5
362			`, newCiphertext, newNonce, newAlias, r.id, tenantID)
363			if err != nil {
364				return fmt.Errorf("failed to update row %s: %w", r.id, err)
365			}
366		}
367	
368		// Mark old key as rotated
369		_, err = tx.Exec(`
370			UPDATE encryption_keys SET status = 'rotated', rotated_at = NOW() WHERE key_alias = $1 AND tenant_id = $2
371		`, oldAlias, tenantID)
372		if err != nil {
373			return fmt.Errorf("failed to mark old key as rotated: %w", err)
374		}
375	
376		return tx.Commit()
377	}
378	
379	// GenerateKeyBytes returns a new random 32-byte encryption key.
380	func (e *EncryptionService) GenerateKeyBytes() []byte {
381		key := make([]byte, 32)
382		if _, err := rand.Read(key); err != nil {
383			panic("failed to generate key: " + err.Error())
384		}
385		return key
386	}
387	
388	// GenerateKey generates a cryptographically secure 32-byte key.
389	func (s *EncryptionService) GenerateKey() ([]byte, error) {
390		key := make([]byte, 32)
391		if _, err := io.ReadFull(rand.Reader, key); err != nil {
392			return nil, fmt.Errorf("failed to generate key: %w", err)
393		}
394		return key, nil
395	}
396	
397	// GetQuarterlyRotationDue returns active keys whose activated_at is more than 90 days ago.
398	func (s *EncryptionService) GetQuarterlyRotationDue(db *sql.DB, tenantID uuid.UUID) ([]models.EncryptionKey, error) {
399		cutoff := time.Now().AddDate(0, 0, -90)
400		rows, err := db.Query(`
401			SELECT id, key_alias, algorithm, status, rotation_number, activated_at, rotated_at, expires_at, created_at
402			FROM encryption_keys
403			WHERE status = 'active' AND activated_at < $1 AND tenant_id = $2
404			ORDER BY activated_at ASC
405		`, cutoff, tenantID)
406		if err != nil {
407			return nil, fmt.Errorf("failed to query keys due for rotation: %w", err)
408		}
409		defer rows.Close()
410	
411		var keys []models.EncryptionKey
412		for rows.Next() {
413			var k models.EncryptionKey
414			if err := rows.Scan(
415				&k.ID, &k.KeyAlias, &k.Algorithm, &k.Status, &k.RotationNumber,
416				&k.ActivatedAt, &k.RotatedAt, &k.ExpiresAt, &k.CreatedAt,
417			); err != nil {
418				return nil, fmt.Errorf("failed to scan key: %w", err)
419			}
420			keys = append(keys, k)
421		}
422	
423		if keys == nil {
424			keys = []models.EncryptionKey{}
425		}
426	
427		return keys, nil
428	}
