			staffID:        "b2c3d4e5-f6a7-8901-bcde-f12345678901",
			clientName:     "",
			scheduledStart: now.Add(time.Hour),
			scheduledEnd:   now.Add(2 * time.Hour),
		}
		errs := validateScheduleRequest(req)
		assertContainsError(t, errs, "client_name is required")
	})

