	"net/http"
	"net/http/httptest"
	"strings"
	"testing"

	"github.com/labstack/echo/v4"
)

// E2E Auth Workflow Tests
// Tests the full authentication lifecycle: login validation, session management,
// cookie handling, and logout flow using Echo's test server.

func TestE2E_LoginInvalidCredentialsFlow(t *testing.T) {
	e := echo.New()

	// Setup a mock login handler that validates request format
	e.POST("/api/auth/login", func(c echo.Context) error {
		var req struct {
			Username string `json:"username"`
			Password string `json:"password"`
		}
		if err := c.Bind(&req); err != nil {
			return c.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid request body"})
		}
		if len(req.Password) < 12 {
			return c.JSON(http.StatusBadRequest, map[string]string{"error": "Password must be at least 12 characters"})
		}
		if req.Username == "" {
			return c.JSON(http.StatusBadRequest, map[string]string{"error": "Username is required"})
		}
		// Simulate invalid credentials
		return c.JSON(http.StatusUnauthorized, map[string]string{"error": "Invalid credentials"})
	})

	t.Run("short password rejected", func(t *testing.T) {
		body := `{"username":"admin","password":"short"}`
		req := httptest.NewRequest(http.MethodPost, "/api/auth/login", strings.NewReader(body))
		req.Header.Set(echo.HeaderContentType, echo.MIMEApplicationJSON)
		rec := httptest.NewRecorder()
		e.ServeHTTP(rec, req)

		if rec.Code != http.StatusBadRequest {
			t.Errorf("status = %d, want %d", rec.Code, http.StatusBadRequest)
		}
	})

	t.Run("empty body rejected", func(t *testing.T) {
		req := httptest.NewRequest(http.MethodPost, "/api/auth/login", strings.NewReader(`{}`))
		req.Header.Set(echo.HeaderContentType, echo.MIMEApplicationJSON)
