func TestE2E_LoginLogoutCookieFlow(t *testing.T) {
	e := echo.New()
	sessionStore := make(map[string]string)

	// Login handler
	e.POST("/api/auth/login", func(c echo.Context) error {
		var req struct {
			Username string `json:"username"`
			Password string `json:"password"`
		}
		if err := c.Bind(&req); err != nil {
			return c.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid request body"})
		}
		if req.Username == "admin" && req.Password == "secure_password_123" {
			token := "test-session-token-xyz"
			sessionStore[token] = req.Username
			c.SetCookie(&http.Cookie{
				Name:     "session_token",
				Value:    token,
				Path:     "/",
				HttpOnly: true,
				Secure:   true,
				SameSite: http.SameSiteStrictMode,
				MaxAge:   1800,
			})
			return c.JSON(http.StatusOK, map[string]interface{}{
				"user": map[string]string{"username": req.Username, "role_name": "Administrator"},
			})
		}
		return c.JSON(http.StatusUnauthorized, map[string]string{"error": "Invalid credentials"})
	})

	// Session check handler
	e.GET("/api/auth/session", func(c echo.Context) error {
		cookie, err := c.Cookie("session_token")
		if err != nil || cookie.Value == "" {
			return c.JSON(http.StatusUnauthorized, map[string]string{"error": "Authentication required"})
		}
		username, ok := sessionStore[cookie.Value]
		if !ok {
			return c.JSON(http.StatusUnauthorized, map[string]string{"error": "Invalid session"})
		}
		return c.JSON(http.StatusOK, map[string]interface{}{
			"user": map[string]string{"username": username},
		})
	})

	// Logout handler
	e.POST("/api/auth/logout", func(c echo.Context) error {
		cookie, err := c.Cookie("session_token")
		if err == nil && cookie.Value != "" {
			delete(sessionStore, cookie.Value)
		}
		c.SetCookie(&http.Cookie{
			Name:     "session_token",
			Value:    "",
			Path:     "/",
			HttpOnly: true,
			Secure:   true,
			SameSite: http.SameSiteStrictMode,
			MaxAge:   -1,
		})
		return c.JSON(http.StatusOK, map[string]string{"message": "Logged out successfully"})
	})

