	var sessionCookie *http.Cookie
	for _, c := range loginRec.Result().Cookies() {
		if c.Name == "session_token" {
			sessionCookie = c
			break
		}
	}
	if sessionCookie == nil {
		t.Fatal("no session_token cookie in login response")
	}
	if sessionCookie.Value == "" {
		t.Fatal("session_token cookie value is empty")
	}
	if !sessionCookie.HttpOnly {
		t.Error("session cookie should be HttpOnly")
	}
	if !sessionCookie.Secure {
		t.Error("session cookie should be Secure")
	}
	if sessionCookie.SameSite != http.SameSiteStrictMode {
		t.Error("session cookie should have SameSite=Strict")
	}

	// Step 2: Check session with cookie
	sessionReq := httptest.NewRequest(http.MethodGet, "/api/auth/session", nil)
	sessionReq.AddCookie(sessionCookie)
	sessionRec := httptest.NewRecorder()
	e.ServeHTTP(sessionRec, sessionReq)

