		t.Errorf("session check with valid cookie: status = %d, want %d", sessionRec.Code, http.StatusOK)
	}

	var sessionResp map[string]interface{}
	json.Unmarshal(sessionRec.Body.Bytes(), &sessionResp)
	if sessionResp["user"] == nil {
		t.Error("session response should contain user data")
	}

	// Step 3: Logout
	logoutReq := httptest.NewRequest(http.MethodPost, "/api/auth/logout", nil)
	logoutReq.AddCookie(sessionCookie)
	logoutRec := httptest.NewRecorder()
	e.ServeHTTP(logoutRec, logoutReq)

	if logoutRec.Code != http.StatusOK {
		t.Errorf("logout status = %d, want %d", logoutRec.Code, http.StatusOK)
	}

	// Step 4: Session check after logout should fail
	postLogoutReq := httptest.NewRequest(http.MethodGet, "/api/auth/session", nil)
	postLogoutReq.AddCookie(sessionCookie) // same old cookie
	postLogoutRec := httptest.NewRecorder()
