func TestE2E_BruteForceProtectionFlow(t *testing.T) {
	e := echo.New()
	failedAttempts := 0
	captchaThreshold := 3
	lockoutThreshold := 5

	e.POST("/api/auth/login", func(c echo.Context) error {
		var req struct {
			Username string `json:"username"`
			Password string `json:"password"`
		}
		if err := c.Bind(&req); err != nil {
			return c.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid request"})
		}
		if len(req.Password) < 12 {
			return c.JSON(http.StatusBadRequest, map[string]string{"error": "Password must be at least 12 characters"})
		}

		failedAttempts++

		if failedAttempts >= lockoutThreshold {
			return c.JSON(http.StatusForbidden, map[string]string{
				"error": "account is locked, try again in 30m0s",
			})
		}
		if failedAttempts >= captchaThreshold {
			return c.JSON(http.StatusBadRequest, map[string]string{
				"error":            "CAPTCHA verification required",
				"captcha_required": "true",
			})
		}
		return c.JSON(http.StatusUnauthorized, map[string]string{"error": "Invalid credentials"})
	})

	// First 2 attempts: just invalid credentials
	for i := 0; i < 2; i++ {
		body := `{"username":"admin","password":"wrong_password_long"}`
		req := httptest.NewRequest(http.MethodPost, "/api/auth/login", strings.NewReader(body))
		req.Header.Set(echo.HeaderContentType, echo.MIMEApplicationJSON)
		rec := httptest.NewRecorder()
		e.ServeHTTP(rec, req)
		if rec.Code != http.StatusUnauthorized {
			t.Errorf("attempt %d: status = %d, want %d", i+1, rec.Code, http.StatusUnauthorized)
		}
	}

	// 3rd attempt: should trigger CAPTCHA
	body := `{"username":"admin","password":"wrong_password_long"}`
	req := httptest.NewRequest(http.MethodPost, "/api/auth/login", strings.NewReader(body))
	req.Header.Set(echo.HeaderContentType, echo.MIMEApplicationJSON)
	rec := httptest.NewRecorder()
	e.ServeHTTP(rec, req)
	if rec.Code != http.StatusBadRequest {
		t.Errorf("attempt 3 (captcha): status = %d, want %d", rec.Code, http.StatusBadRequest)
	}
	var resp map[string]string
	json.Unmarshal(rec.Body.Bytes(), &resp)
	if resp["captcha_required"] != "true" {
		t.Error("3rd attempt should require CAPTCHA")
	}

	// 5th attempt: should lock account
	for i := 3; i < 4; i++ {
		req := httptest.NewRequest(http.MethodPost, "/api/auth/login", strings.NewReader(body))
		req.Header.Set(echo.HeaderContentType, echo.MIMEApplicationJSON)
		rec := httptest.NewRecorder()
		e.ServeHTTP(rec, req)
	}

	req = httptest.NewRequest(http.MethodPost, "/api/auth/login", strings.NewReader(body))
	req.Header.Set(echo.HeaderContentType, echo.MIMEApplicationJSON)
	rec = httptest.NewRecorder()
	e.ServeHTTP(rec, req)
	if rec.Code != http.StatusForbidden {
		t.Errorf("attempt 5 (lockout): status = %d, want %d", rec.Code, http.StatusForbidden)
	}
}

