package tests

import (
	"encoding/json"
	"net/http"
	"net/http/httptest"
	"strings"
	"testing"
	"time"

	"github.com/labstack/echo/v4"
)

// E2E Governance Workflow Tests
// Tests the complete content governance lifecycle: create -> submit -> review -> gray-release -> publish.

type contentItem struct {
	ID            string     `json:"id"`
	Title         string     `json:"title"`
	Body          string     `json:"body"`
	ContentType   string     `json:"content_type"`
	Status        string     `json:"status"`
	GrayReleaseAt *time.Time `json:"gray_release_at,omitempty"`
	Version       int        `json:"current_version"`
}

func TestE2E_ContentLifecycleWorkflow(t *testing.T) {
	e := echo.New()
	contents := make(map[string]*contentItem)
	reviews := make(map[string]map[string]string) // reviewID -> {content_id, status, decision}

	// CREATE content
	e.POST("/api/governance/content", func(c echo.Context) error {
		var req struct {
			Title       string `json:"title"`
			Body        string `json:"body"`
			ContentType string `json:"content_type"`
		}
		if err := c.Bind(&req); err != nil {
			return c.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid request body"})
		}
		if req.Title == "" || req.Body == "" {
			return c.JSON(http.StatusBadRequest, map[string]string{"error": "title and body are required"})
		}
		validTypes := map[string]bool{"article": true, "resource": true, "announcement": true, "policy": true}
		if !validTypes[req.ContentType] {
			return c.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid content_type"})
		}

		id := "content-001"
		item := &contentItem{
			ID:          id,
			Title:       req.Title,
			Body:        req.Body,
			ContentType: req.ContentType,
			Status:      "draft",
			Version:     1,
		}
		contents[id] = item
		return c.JSON(http.StatusCreated, item)
	})

	// SUBMIT for review
	e.POST("/api/governance/content/:id/submit", func(c echo.Context) error {
		id := c.Param("id")
		item, ok := contents[id]
		if !ok {
			return c.JSON(http.StatusNotFound, map[string]string{"error": "Not found"})
		}
		if item.Status != "draft" && item.Status != "rejected" {
			return c.JSON(http.StatusBadRequest, map[string]string{"error": "Can only submit from draft or rejected"})
		}
		item.Status = "pending_review"

		reviewID := "review-001"
		reviews[reviewID] = map[string]string{
			"content_id": id,
			"status":     "pending",
		}

		return c.JSON(http.StatusOK, item)
	})

	// REVIEW decision
	e.POST("/api/governance/reviews/:id/decide", func(c echo.Context) error {
		reviewID := c.Param("id")
		review, ok := reviews[reviewID]
		if !ok {
			return c.JSON(http.StatusNotFound, map[string]string{"error": "Review not found"})
		}

