package tests

import (
	"encoding/json"
	"net/http"
	"net/http/httptest"
	"strings"
	"testing"
	"time"

	"github.com/labstack/echo/v4"
)

// E2E Scheduling Workflow Tests
// Tests the complete scheduling lifecycle: create, conflict detection, confirmation,
// backup staff, and cancellation flow.

type schedule struct {
	ID             string    `json:"id"`
	ServiceID      string    `json:"service_id"`
	StaffID        string    `json:"staff_id"`
	ClientName     string    `json:"client_name"`
	ScheduledStart time.Time `json:"scheduled_start"`
	ScheduledEnd   time.Time `json:"scheduled_end"`
	Status         string    `json:"status"`
	ConfirmedAt    *string   `json:"confirmed_at,omitempty"`
}

func TestE2E_ScheduleConflictDetection(t *testing.T) {
	e := echo.New()
	schedules := make(map[string]*schedule)
	bufferMinutes := 30

	e.POST("/api/schedules", func(c echo.Context) error {
		var req struct {
			ServiceID      string `json:"service_id"`
			StaffID        string `json:"staff_id"`
			ClientName     string `json:"client_name"`
			ScheduledStart string `json:"scheduled_start"`
			ScheduledEnd   string `json:"scheduled_end"`
		}
		if err := c.Bind(&req); err != nil {
			return c.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid request"})
		}
		if req.ClientName == "" || req.StaffID == "" || req.ServiceID == "" {
			return c.JSON(http.StatusBadRequest, map[string]string{"error": "Missing required fields"})
		}

		start, _ := time.Parse(time.RFC3339, req.ScheduledStart)
		end, _ := time.Parse(time.RFC3339, req.ScheduledEnd)

		if !end.After(start) {
			return c.JSON(http.StatusBadRequest, map[string]string{"error": "End must be after start"})
		}

		// Check conflicts with buffer
		bufferDuration := time.Duration(bufferMinutes) * time.Minute
		for _, existing := range schedules {
			if existing.StaffID == req.StaffID && existing.Status != "cancelled" {
				bufferedStart := start.Add(-bufferDuration)
				bufferedEnd := end.Add(bufferDuration)
				if existing.ScheduledStart.Before(bufferedEnd) && existing.ScheduledEnd.After(bufferedStart) {
					return c.JSON(http.StatusConflict, map[string]string{
						"error":       "Schedule conflict detected",
						"conflict_id": existing.ID,
					})
				}
			}
		}

		id := "sched-" + req.ClientName
		sched := &schedule{
			ID:             id,
			ServiceID:      req.ServiceID,
			StaffID:        req.StaffID,
			ClientName:     req.ClientName,
			ScheduledStart: start,
			ScheduledEnd:   end,
			Status:         "pending",
		}
		schedules[id] = sched
		return c.JSON(http.StatusCreated, sched)
	})

	// Cancel endpoint
	e.DELETE("/api/schedules/:id", func(c echo.Context) error {
		id := c.Param("id")
		sched, ok := schedules[id]
		if !ok {
			return c.JSON(http.StatusNotFound, map[string]string{"error": "Not found"})
		}
		sched.Status = "cancelled"
