	"github.com/labstack/echo/v4"
)

// E2E Reconciliation Workflow Tests
// Tests the complete reconciliation lifecycle: import, match, exception handling, resolution.

type transaction struct {
	ID              string    `json:"id"`
	Amount          float64   `json:"amount"`
	Counterparty    string    `json:"counterparty"`
	Memo            string    `json:"memo"`
	TransactionDate time.Time `json:"transaction_date"`
	Source          string    `json:"source"`
	Matched         bool      `json:"matched"`
}

type matchResult struct {
	MatchedCount   int     `json:"matched_count"`
	ExceptionCount int     `json:"exception_count"`
	TotalInternal  int     `json:"total_internal"`
	TotalExternal  int     `json:"total_external"`
}

func TestE2E_ReconciliationMatchingWorkflow(t *testing.T) {
	e := echo.New()

	// In-memory stores
	feeds := map[string]string{}
	transactions := map[string][]transaction{}
	exceptions := map[string]map[string]string{}

	// Import endpoint
	e.POST("/api/reconciliation/import", func(c echo.Context) error {
		feedID := "feed-001"
		feeds[feedID] = "processing"

		// Simulate imported transactions
		now := time.Now()
		transactions[feedID] = []transaction{
			{ID: "tx-int-1", Amount: 500.00, Counterparty: "Acme Corp", Memo: "Invoice #1001", TransactionDate: now, Source: "internal"},
			{ID: "tx-int-2", Amount: 250.50, Counterparty: "Beta Inc", Memo: "Service fee", TransactionDate: now, Source: "internal"},
			{ID: "tx-int-3", Amount: 1000.00, Counterparty: "Gamma LLC", Memo: "Consulting", TransactionDate: now, Source: "internal"},
			{ID: "tx-ext-1", Amount: 500.00, Counterparty: "Acme Corp", Memo: "Invoice #1001", TransactionDate: now.Add(5 * time.Minute), Source: "external"},
			{ID: "tx-ext-2", Amount: 250.00, Counterparty: "Beta Inc", Memo: "Service fees", TransactionDate: now.Add(3 * time.Minute), Source: "external"},
			{ID: "tx-ext-3", Amount: 2000.00, Counterparty: "Delta Corp", Memo: "Purchase order", TransactionDate: now, Source: "external"},
		}
		feeds[feedID] = "pending"

		return c.JSON(http.StatusCreated, map[string]interface{}{
			"feed_id":          feedID,
			"records_imported": len(transactions[feedID]),
		})
	})

	// Match endpoint
	e.POST("/api/reconciliation/feeds/:id/match", func(c echo.Context) error {
		feedID := c.Param("id")
		txs, ok := transactions[feedID]
		if !ok {
			return c.JSON(http.StatusNotFound, map[string]string{"error": "Feed not found"})
		}

		var internal, external []transaction
		for _, tx := range txs {
			if tx.Source == "internal" {
				internal = append(internal, tx)
			} else {
				external = append(external, tx)
			}
		}

		result := matchResult{
			TotalInternal: len(internal),
			TotalExternal: len(external),
		}

		// Simple matching: amount + counterparty + time window
		matchedExt := map[string]bool{}
		for _, intTx := range internal {
			bestScore := 0.0
			bestExtID := ""

			for _, extTx := range external {
				if matchedExt[extTx.ID] {
					continue
				}
				score := 0.0
				// Amount
				if math.Abs(intTx.Amount-extTx.Amount) == 0 {
					score += 40
				} else if math.Abs(intTx.Amount-extTx.Amount) <= 1.00 {
					score += 20
				}
				// Time
				if math.Abs(intTx.TransactionDate.Sub(extTx.TransactionDate).Minutes()) <= 10 {
					score += 30
				}
				// Counterparty
				if strings.EqualFold(intTx.Counterparty, extTx.Counterparty) {
					score += 15
				}

				if score > bestScore {
					bestScore = score
					bestExtID = extTx.ID
				}
			}

			if bestScore >= 70 && bestExtID != "" {
				matchedExt[bestExtID] = true
				result.MatchedCount++
			} else if bestScore >= 50 {
				// Manual review exception
				excID := "exc-manual-" + intTx.ID
				exceptions[excID] = map[string]string{
					"type":   "unmatched",
					"status": "open",
					"amount": strings.TrimRight(strings.TrimRight(
						func() string { b, _ := json.Marshal(intTx.Amount); return string(b) }(), "0"), "."),
				}
				result.ExceptionCount++
			} else {
				// Unmatched
				excID := "exc-" + intTx.ID
				exceptions[excID] = map[string]string{
					"type":   "unmatched",
					"status": "open",
				}
				result.ExceptionCount++
			}
		}

		// Unmatched external
		for _, extTx := range external {
			if !matchedExt[extTx.ID] {
				excID := "exc-" + extTx.ID
				exceptions[excID] = map[string]string{
					"type":   "unmatched",
					"status": "open",
				}
				result.ExceptionCount++
			}
		}

		feeds[feedID] = "completed"
		return c.JSON(http.StatusOK, result)
	})

	// List exceptions
	e.GET("/api/reconciliation/exceptions", func(c echo.Context) error {
		list := make([]map[string]string, 0)
		for id, exc := range exceptions {
			exc["id"] = id
			list = append(list, exc)
		}
		return c.JSON(http.StatusOK, list)
	})

	// Resolve exception
	e.PUT("/api/reconciliation/exceptions/:id/resolve", func(c echo.Context) error {
		excID := c.Param("id")
		exc, ok := exceptions[excID]
		if !ok {
			return c.JSON(http.StatusNotFound, map[string]string{"error": "Exception not found"})
		}

		var req struct {
			Disposition     string `json:"disposition"`
			ResolutionNotes string `json:"resolution_notes"`
		}
		if err := c.Bind(&req); err != nil {
			return c.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid request"})
		}
		if req.Disposition == "" {
			return c.JSON(http.StatusBadRequest, map[string]string{"error": "disposition is required"})
		}

		exc["status"] = "resolved"
		exc["disposition"] = req.Disposition
		return c.JSON(http.StatusOK, exc)
	})

	// --- Workflow ---

	// Step 1: Import feed
	importRec := doPost(e, "/api/reconciliation/import", `{}`)
	if importRec.Code != http.StatusCreated {
		t.Fatalf("import: status = %d, want %d", importRec.Code, http.StatusCreated)
	}

	// Step 2: Run matching
	matchRec := doPost(e, "/api/reconciliation/feeds/feed-001/match", `{}`)
	if matchRec.Code != http.StatusOK {
		t.Fatalf("match: status = %d, want %d", matchRec.Code, http.StatusOK)
	}

	var result matchResult
	json.Unmarshal(matchRec.Body.Bytes(), &result)

	if result.TotalInternal != 3 {
		t.Errorf("total internal = %d, want 3", result.TotalInternal)
	}
	if result.TotalExternal != 3 {
		t.Errorf("total external = %d, want 3", result.TotalExternal)
	}
	if result.MatchedCount < 1 {
		t.Error("expected at least 1 auto-match (Acme Corp exact match)")
	}
	if result.ExceptionCount < 1 {
		t.Error("expected at least 1 exception (Delta Corp unmatched)")
	}

	// Step 3: List exceptions
	excReq := httptest.NewRequest(http.MethodGet, "/api/reconciliation/exceptions", nil)
	excRec := httptest.NewRecorder()
	e.ServeHTTP(excRec, excReq)
	if excRec.Code != http.StatusOK {
		t.Fatalf("list exceptions: status = %d, want %d", excRec.Code, http.StatusOK)
	}

	var excList []map[string]string
	json.Unmarshal(excRec.Body.Bytes(), &excList)
	if len(excList) == 0 {
		t.Fatal("expected at least 1 exception")
	}

	// Step 4: Resolve an exception
	excID := excList[0]["id"]
	resolveBody := `{"disposition":"write_off","resolution_notes":"Confirmed as valid variance"}`
	resolveReq := httptest.NewRequest(http.MethodPut, "/api/reconciliation/exceptions/"+excID+"/resolve",
		strings.NewReader(resolveBody))
	resolveReq.Header.Set(echo.HeaderContentType, echo.MIMEApplicationJSON)
	resolveRec := httptest.NewRecorder()
	e.ServeHTTP(resolveRec, resolveReq)

	if resolveRec.Code != http.StatusOK {
		t.Errorf("resolve: status = %d, want %d", resolveRec.Code, http.StatusOK)
	}

	var resolved map[string]string
	json.Unmarshal(resolveRec.Body.Bytes(), &resolved)
	if resolved["status"] != "resolved" {
		t.Errorf("resolved status = %q, want resolved", resolved["status"])
	}
	if resolved["disposition"] != "write_off" {
		t.Errorf("disposition = %q, want write_off", resolved["disposition"])
	}
}

func TestE2E_ExceptionResolutionValidation(t *testing.T) {
	e := echo.New()

	e.PUT("/api/reconciliation/exceptions/:id/resolve", func(c echo.Context) error {
		var req struct {
			Disposition     string `json:"disposition"`
			ResolutionNotes string `json:"resolution_notes"`
		}
		if err := c.Bind(&req); err != nil {
			return c.JSON(http.StatusBadRequest, map[string]string{"error": "Invalid request"})
		}
		if req.Disposition == "" {
			return c.JSON(http.StatusBadRequest, map[string]string{"error": "disposition is required"})
		}
		return c.JSON(http.StatusOK, map[string]string{"status": "resolved"})
	})

	t.Run("missing disposition rejected", func(t *testing.T) {
		body := `{"resolution_notes":"test"}`
		req := httptest.NewRequest(http.MethodPut, "/api/reconciliation/exceptions/exc-001/resolve",
			strings.NewReader(body))
		req.Header.Set(echo.HeaderContentType, echo.MIMEApplicationJSON)
		rec := httptest.NewRecorder()
		e.ServeHTTP(rec, req)
		if rec.Code != http.StatusBadRequest {
			t.Errorf("status = %d, want %d", rec.Code, http.StatusBadRequest)
		}
	})

	t.Run("valid resolution accepted", func(t *testing.T) {
		body := `{"disposition":"adjusted","resolution_notes":"Amount corrected"}`
		req := httptest.NewRequest(http.MethodPut, "/api/reconciliation/exceptions/exc-001/resolve",
			strings.NewReader(body))
		req.Header.Set(echo.HeaderContentType, echo.MIMEApplicationJSON)
		rec := httptest.NewRecorder()
		e.ServeHTTP(rec, req)
		if rec.Code != http.StatusOK {
			t.Errorf("status = %d, want %d", rec.Code, http.StatusOK)
		}
	})
}

