	loginReq.Header.Set("Content-Type", "application/json")
	loginRec := httptest.NewRecorder()
	e.ServeHTTP(loginRec, loginReq)

	if loginRec.Code != 200 {
		t.Fatalf("login: status=%d, want 200", loginRec.Code)
	}

	// Verify cookie security attributes
	var sessionCookie *http.Cookie
	for _, c := range loginRec.Result().Cookies() {
		if c.Name == "session_token" {
			sessionCookie = c
		}
	}
	if sessionCookie == nil {
		t.Fatal("no session_token cookie")
	}
	if !sessionCookie.HttpOnly {
		t.Error("cookie must be HttpOnly")
	}
	if !sessionCookie.Secure {
		t.Error("cookie must be Secure")
	}
	if sessionCookie.SameSite != http.SameSiteStrictMode {
		t.Error("cookie must be SameSite=Strict")
	}

	// Verify response body
	var loginResp map[string]interface{}
	json.Unmarshal(loginRec.Body.Bytes(), &loginResp)
	if loginResp["user"] == nil {
		t.Error("login response must contain user field")
	}

	// Step 2: Session check with cookie
	sessReq := httptest.NewRequest(http.MethodGet, "/api/auth/session", nil)
	sessReq.AddCookie(sessionCookie)
	sessRec := httptest.NewRecorder()
	e.ServeHTTP(sessRec, sessReq)
	if sessRec.Code != 200 {
		t.Errorf("session check: status=%d, want 200", sessRec.Code)
	}

	// Step 3: Session check without cookie => 401
	noAuthReq := httptest.NewRequest(http.MethodGet, "/api/auth/session", nil)
	noAuthRec := httptest.NewRecorder()
	e.ServeHTTP(noAuthRec, noAuthReq)
	if noAuthRec.Code != 401 {
		t.Errorf("unauthenticated session: status=%d, want 401", noAuthRec.Code)
	}

	// Step 4: Logout
	logoutReq := httptest.NewRequest(http.MethodPost, "/api/auth/logout", nil)
	logoutReq.AddCookie(sessionCookie)
	logoutRec := httptest.NewRecorder()
	e.ServeHTTP(logoutRec, logoutReq)
	if logoutRec.Code != 200 {
		t.Errorf("logout: status=%d, want 200", logoutRec.Code)
	}

	// Step 5: Session check after logout => 401
	postLogoutReq := httptest.NewRequest(http.MethodGet, "/api/auth/session", nil)
	postLogoutReq.AddCookie(sessionCookie)
	postLogoutRec := httptest.NewRecorder()
	e.ServeHTTP(postLogoutRec, postLogoutReq)
	if postLogoutRec.Code != 401 {
		t.Errorf("post-logout session: status=%d, want 401", postLogoutRec.Code)
	}
}

func TestAuthWorkflow_BruteForceEscalation(t *testing.T) {
	e := echo.New()
	failCount := 0

	e.POST("/api/auth/login", func(c echo.Context) error {
		var req struct {
			Username string `json:"username"`
			Password string `json:"password"`
		}
		if err := c.Bind(&req); err != nil {
			return c.JSON(400, map[string]string{"error": "bad request"})
		}
		if len(req.Password) < 12 {
			return c.JSON(400, map[string]string{"error": "Password must be at least 12 characters"})
		}
		failCount++
		if failCount >= 5 {
			return c.JSON(403, map[string]string{"error": "account is locked"})
		}
		if failCount >= 3 {
			return c.JSON(400, map[string]string{"error": "CAPTCHA verification required", "captcha_required": "true"})
		}
		return c.JSON(401, map[string]string{"error": "Invalid credentials"})
	})

	body := `{"username":"admin","password":"wrong_password_1"}`

	// Attempts 1-2: 401
	for i := 0; i < 2; i++ {
		rec := httptest.NewRecorder()
		e.ServeHTTP(rec, httptest.NewRequest(http.MethodPost, "/api/auth/login", strings.NewReader(body)))
		if rec.Code != 401 {
			t.Errorf("attempt %d: status=%d, want 401", i+1, rec.Code)
		}
	}

	// Attempt 3: CAPTCHA (400)
	rec3 := httptest.NewRecorder()
	e.ServeHTTP(rec3, httptest.NewRequest(http.MethodPost, "/api/auth/login", strings.NewReader(body)))
	if rec3.Code != 400 {
		t.Errorf("attempt 3: status=%d, want 400 (CAPTCHA)", rec3.Code)
	}
	var resp3 map[string]string
	json.Unmarshal(rec3.Body.Bytes(), &resp3)
	if resp3["captcha_required"] != "true" {
		t.Error("attempt 3 should include captcha_required=true")
	}

	// Attempt 4: still CAPTCHA
	rec4 := httptest.NewRecorder()
	e.ServeHTTP(rec4, httptest.NewRequest(http.MethodPost, "/api/auth/login", strings.NewReader(body)))
	if rec4.Code != 400 {
		t.Errorf("attempt 4: status=%d, want 400", rec4.Code)
	}

	// Attempt 5: lockout (403)
	rec5 := httptest.NewRecorder()
	e.ServeHTTP(rec5, httptest.NewRequest(http.MethodPost, "/api/auth/login", strings.NewReader(body)))
	if rec5.Code != 403 {
		t.Errorf("attempt 5: status=%d, want 403 (locked)", rec5.Code)
	}
}

