package tests

import (
	"encoding/json"
	"net/http"
	"net/http/httptest"
	"strings"
	"testing"
	"time"

	"github.com/labstack/echo/v4"
)

// Integration tests for the content governance workflow.
// Validates the state machine: draft -> pending_review -> approved -> gray_release -> published.
// True e2e tests against the live stack run via API_tests/full_coverage_test.sh.

type contentState struct {
	ID            string     `json:"id"`
	Title         string     `json:"title"`
	Status        string     `json:"status"`
	GrayReleaseAt *time.Time `json:"gray_release_at,omitempty"`
}

func setupGovernanceEcho() (*echo.Echo, map[string]*contentState, map[string]string) {
	e := echo.New()
	contents := map[string]*contentState{}
	reviews := map[string]string{} // reviewID -> contentID

	e.POST("/api/governance/content", func(c echo.Context) error {
		var req struct {
			Title       string `json:"title"`
			Body        string `json:"body"`
			ContentType string `json:"content_type"`
		}
		if err := c.Bind(&req); err != nil {
			return c.JSON(400, map[string]string{"error": "Invalid request body"})
		}
		if req.Title == "" || req.Body == "" {
			return c.JSON(400, map[string]string{"error": "title and body are required"})
		}
		validTypes := map[string]bool{"article": true, "resource": true, "announcement": true, "policy": true}
		if !validTypes[req.ContentType] {
			return c.JSON(400, map[string]string{"error": "Invalid content_type"})
		}
		id := "content-001"
		contents[id] = &contentState{ID: id, Title: req.Title, Status: "draft"}
		return c.JSON(201, contents[id])
	})

	e.POST("/api/governance/content/:id/submit", func(c echo.Context) error {
		id := c.Param("id")
		item, ok := contents[id]
		if !ok {
			return c.JSON(404, map[string]string{"error": "Not found"})
		}
		if item.Status != "draft" && item.Status != "rejected" {
			return c.JSON(400, map[string]string{"error": "Can only submit from draft or rejected"})
		}
		item.Status = "pending_review"
		reviews["review-001"] = id
		return c.JSON(200, item)
	})

	e.POST("/api/governance/reviews/:id/decide", func(c echo.Context) error {
		rid := c.Param("id")
		contentID, ok := reviews[rid]
		if !ok {
			return c.JSON(404, map[string]string{"error": "Review not found"})
		}
		var req struct{ Decision string `json:"decision"` }
		if err := c.Bind(&req); err != nil {
			return c.JSON(400, map[string]string{"error": "Invalid request"})
		}
		if req.Decision != "approved" && req.Decision != "rejected" && req.Decision != "escalated" {
			return c.JSON(400, map[string]string{"error": "Invalid decision"})
		}
		item := contents[contentID]
		switch req.Decision {
		case "approved":
			item.Status = "approved"
		case "rejected":
			item.Status = "rejected"
		case "escalated":
			item.Status = "in_review"
		}
		return c.JSON(200, map[string]string{"status": "decided"})
	})

	e.POST("/api/governance/content/:id/promote", func(c echo.Context) error {
		id := c.Param("id")
		item, ok := contents[id]
		if !ok {
			return c.JSON(404, map[string]string{"error": "Not found"})
		}
		if item.Status == "approved" {
			now := time.Now()
			item.Status = "gray_release"
			item.GrayReleaseAt = &now
			return c.JSON(200, item)
		}
		if item.Status == "gray_release" {
			if item.GrayReleaseAt != nil && time.Since(*item.GrayReleaseAt) >= 24*time.Hour {
				item.Status = "published"
				return c.JSON(200, item)
			}
			return c.JSON(400, map[string]string{"error": "24-hour gray-release period not yet elapsed"})
		}
		return c.JSON(400, map[string]string{"error": "Cannot promote from " + item.Status})
	})

	return e, contents, reviews
}

func TestGovernanceWorkflow_FullLifecycle(t *testing.T) {
	e, contents, _ := setupGovernanceEcho()

	post := func(path, body string) *httptest.ResponseRecorder {
		req := httptest.NewRequest(http.MethodPost, path, strings.NewReader(body))
		req.Header.Set("Content-Type", "application/json")
		rec := httptest.NewRecorder()
		e.ServeHTTP(rec, req)
		return rec
	}

	// Create
	rec := post("/api/governance/content", `{"title":"Policy","body":"Content","content_type":"policy"}`)
	if rec.Code != 201 {
		t.Fatalf("create: %d", rec.Code)
	}

	// Submit
	rec = post("/api/governance/content/content-001/submit", "")
	if rec.Code != 200 || contents["content-001"].Status != "pending_review" {
		t.Fatalf("submit: code=%d, status=%s", rec.Code, contents["content-001"].Status)
	}

	// Approve
	rec = post("/api/governance/reviews/review-001/decide", `{"decision":"approved"}`)
	if rec.Code != 200 || contents["content-001"].Status != "approved" {
		t.Fatalf("approve: code=%d, status=%s", rec.Code, contents["content-001"].Status)
	}

	// Promote to gray-release
	rec = post("/api/governance/content/content-001/promote", "")
	if rec.Code != 200 || contents["content-001"].Status != "gray_release" {
		t.Fatalf("gray-release: code=%d, status=%s", rec.Code, contents["content-001"].Status)
	}

	// Early publish attempt → 400
	rec = post("/api/governance/content/content-001/promote", "")
	if rec.Code != 400 {
		t.Errorf("early publish: %d, want 400", rec.Code)
	}

	// Simulate 24h elapsed
	past := time.Now().Add(-25 * time.Hour)
	contents["content-001"].GrayReleaseAt = &past

	// Publish
	rec = post("/api/governance/content/content-001/promote", "")
	if rec.Code != 200 || contents["content-001"].Status != "published" {
		t.Errorf("publish: code=%d, status=%s", rec.Code, contents["content-001"].Status)
	}
}

func TestGovernanceWorkflow_RejectionAndResubmit(t *testing.T) {
	e, contents, _ := setupGovernanceEcho()

	post := func(path, body string) *httptest.ResponseRecorder {
		req := httptest.NewRequest(http.MethodPost, path, strings.NewReader(body))
		req.Header.Set("Content-Type", "application/json")
		rec := httptest.NewRecorder()
		e.ServeHTTP(rec, req)
		return rec
	}

