	post("/api/governance/content/content-001/submit", "")

	// Reject
	post("/api/governance/reviews/review-001/decide", `{"decision":"rejected"}`)
	if contents["content-001"].Status != "rejected" {
		t.Errorf("after reject: %s, want rejected", contents["content-001"].Status)
	}

	// Re-submit
	post("/api/governance/content/content-001/submit", "")
	if contents["content-001"].Status != "pending_review" {
		t.Errorf("after re-submit: %s, want pending_review", contents["content-001"].Status)
	}
}

