	e, _, _ := setupGovernanceEcho()
	invalid := []string{"blog", "page", ""}

	for _, ct := range invalid {
		body := `{"title":"T","body":"B","content_type":"` + ct + `"}`
		req := httptest.NewRequest(http.MethodPost, "/api/governance/content", strings.NewReader(body))
