		rec := httptest.NewRecorder()
		e.ServeHTTP(rec, req)
		if rec.Code != 400 {
			t.Errorf("type %q: %d, want 400", ct, rec.Code)
		}
	}
}

func TestGovernanceWorkflow_InvalidReviewDecision(t *testing.T) {
	e, _, _ := setupGovernanceEcho()

	// Setup content and submit
	post := func(path, body string) {
		req := httptest.NewRequest(http.MethodPost, path, strings.NewReader(body))
		req.Header.Set("Content-Type", "application/json")
		rec := httptest.NewRecorder()
		e.ServeHTTP(rec, req)
	}
	post("/api/governance/content", `{"title":"T","body":"B","content_type":"article"}`)
	post("/api/governance/content/content-001/submit", "")

	invalid := []string{"accept", "deny", ""}
	for _, d := range invalid {
		b, _ := json.Marshal(map[string]string{"decision": d})
		req := httptest.NewRequest(http.MethodPost, "/api/governance/reviews/review-001/decide", strings.NewReader(string(b)))
		req.Header.Set("Content-Type", "application/json")
		rec := httptest.NewRecorder()
		e.ServeHTTP(rec, req)
		if rec.Code != 400 {
			t.Errorf("decision %q: %d, want 400", d, rec.Code)
		}
	}
}

