func TestScheduleWorkflow_ConflictDetectionWith30MinBuffer(t *testing.T) {
	e := echo.New()
	type sched struct {
		ID, StaffID    string
		Start, End     time.Time
		Status         string
	}
	schedules := map[string]*sched{}
	buf := 30 * time.Minute

	e.POST("/api/schedules", func(c echo.Context) error {
		var req struct {
			ServiceID string `json:"service_id"`
