package tests

import (
	"encoding/json"
	"math"
	"net/http"
	"net/http/httptest"
	"strings"
	"testing"
	"time"

	"github.com/labstack/echo/v4"
)

// Integration tests for the reconciliation workflow.
// Validates matching algorithm thresholds, exception generation, and resolution.
// True e2e tests against the live stack run via API_tests/full_coverage_test.sh.

func TestReconciliationWorkflow_MatchAndResolve(t *testing.T) {
	e := echo.New()
	type tx struct {
		ID, Counterparty string
		Amount           float64
		Date             time.Time
		Source           string
	}

	now := time.Now()
	transactions := []tx{
		{"int-1", "Acme Corp", 500.00, now, "internal"},
		{"int-2", "Beta Inc", 250.50, now, "internal"},
		{"ext-1", "Acme Corp", 500.00, now.Add(5 * time.Minute), "external"},
		{"ext-2", "Delta Corp", 2000.00, now, "external"},
	}
	exceptions := map[string]map[string]string{}

	e.POST("/api/reconciliation/feeds/:id/match", func(c echo.Context) error {
		var internal, external []tx
		for _, t := range transactions {
			if t.Source == "internal" {
				internal = append(internal, t)
			} else {
				external = append(external, t)
			}
		}
		matched, excCount := 0, 0
		usedExt := map[string]bool{}

		for _, intTx := range internal {
			bestScore, bestID := 0.0, ""
			for _, extTx := range external {
				if usedExt[extTx.ID] {
					continue
				}
				score := 0.0
				if math.Abs(intTx.Amount-extTx.Amount) == 0 {
					score += 40
				} else if math.Abs(intTx.Amount-extTx.Amount) <= 1 {
					score += 20
				}
				if math.Abs(intTx.Date.Sub(extTx.Date).Minutes()) <= 10 {
					score += 30
				}
				if strings.EqualFold(intTx.Counterparty, extTx.Counterparty) {
					score += 15
				}
				if score > bestScore {
					bestScore, bestID = score, extTx.ID
				}
			}
			if bestScore >= 70 {
				usedExt[bestID] = true
				matched++
			} else {
				eid := "exc-" + intTx.ID
				exceptions[eid] = map[string]string{"type": "unmatched", "status": "open"}
				excCount++
			}
		}
		for _, extTx := range external {
			if !usedExt[extTx.ID] {
				eid := "exc-" + extTx.ID
				exceptions[eid] = map[string]string{"type": "unmatched", "status": "open"}
				excCount++
			}
		}
		return c.JSON(200, map[string]int{"matched_count": matched, "exception_count": excCount})
	})

	e.GET("/api/reconciliation/exceptions", func(c echo.Context) error {
		list := []map[string]string{}
		for id, exc := range exceptions {
			item := map[string]string{"id": id}
			for k, v := range exc {
				item[k] = v
			}
			list = append(list, item)
		}
		return c.JSON(200, list)
	})

	e.PUT("/api/reconciliation/exceptions/:id/resolve", func(c echo.Context) error {
		exc, ok := exceptions[c.Param("id")]
		if !ok {
			return c.JSON(404, map[string]string{"error": "not found"})
		}
		var req struct {
			Disposition string `json:"disposition"`
			Notes       string `json:"resolution_notes"`
		}
		if err := c.Bind(&req); err != nil {
			return c.JSON(400, map[string]string{"error": "bad request"})
		}
		if req.Disposition == "" {
			return c.JSON(400, map[string]string{"error": "disposition required"})
		}
		exc["status"] = "resolved"
		exc["disposition"] = req.Disposition
		return c.JSON(200, exc)
	})

	// Run matching
	matchReq := httptest.NewRequest(http.MethodPost, "/api/reconciliation/feeds/f1/match", nil)
	matchRec := httptest.NewRecorder()
	e.ServeHTTP(matchRec, matchReq)
	if matchRec.Code != 200 {
		t.Fatalf("match: %d", matchRec.Code)
	}
	var result map[string]int
	json.Unmarshal(matchRec.Body.Bytes(), &result)
	if result["matched_count"] < 1 {
		t.Error("expected at least 1 match (Acme Corp)")
	}
	if result["exception_count"] < 1 {
		t.Error("expected at least 1 exception (Delta Corp / Beta Inc unmatched)")
	}

	// List exceptions
	excReq := httptest.NewRequest(http.MethodGet, "/api/reconciliation/exceptions", nil)
	excRec := httptest.NewRecorder()
	e.ServeHTTP(excRec, excReq)
	if excRec.Code != 200 {
		t.Fatalf("list exceptions: %d", excRec.Code)
	}
	var excList []map[string]string
	json.Unmarshal(excRec.Body.Bytes(), &excList)
	if len(excList) == 0 {
		t.Fatal("expected exceptions")
	}

	// Resolve first exception
	resolveBody := `{"disposition":"write_off","resolution_notes":"Test resolution"}`
	resolveReq := httptest.NewRequest(http.MethodPut,
		"/api/reconciliation/exceptions/"+excList[0]["id"]+"/resolve",
		strings.NewReader(resolveBody))
	resolveReq.Header.Set("Content-Type", "application/json")
	resolveRec := httptest.NewRecorder()
	e.ServeHTTP(resolveRec, resolveReq)
	if resolveRec.Code != 200 {
		t.Errorf("resolve: %d", resolveRec.Code)
	}
	var resolved map[string]string
	json.Unmarshal(resolveRec.Body.Bytes(), &resolved)
	if resolved["status"] != "resolved" {
		t.Errorf("status=%s, want resolved", resolved["status"])
	}
}

func TestReconciliationWorkflow_ResolutionValidation(t *testing.T) {
	e := echo.New()
	e.PUT("/api/reconciliation/exceptions/:id/resolve", func(c echo.Context) error {
		var req struct {
			Disposition string `json:"disposition"`
		}
		if err := c.Bind(&req); err != nil {
			return c.JSON(400, map[string]string{"error": "bad"})
		}
		if req.Disposition == "" {
			return c.JSON(400, map[string]string{"error": "disposition required"})
		}
		return c.JSON(200, map[string]string{"status": "resolved"})
	})

	// Missing disposition → 400
	req := httptest.NewRequest(http.MethodPut, "/api/reconciliation/exceptions/e1/resolve",
		strings.NewReader(`{"resolution_notes":"test"}`))
	req.Header.Set("Content-Type", "application/json")
	rec := httptest.NewRecorder()
	e.ServeHTTP(rec, req)
	if rec.Code != 400 {
		t.Errorf("missing disposition: %d, want 400", rec.Code)
	}

	// Valid → 200
	req2 := httptest.NewRequest(http.MethodPut, "/api/reconciliation/exceptions/e1/resolve",
		strings.NewReader(`{"disposition":"adjusted","resolution_notes":"corrected"}`))
	req2.Header.Set("Content-Type", "application/json")
	rec2 := httptest.NewRecorder()
	e.ServeHTTP(rec2, req2)
	if rec2.Code != 200 {
		t.Errorf("valid resolution: %d, want 200", rec2.Code)
	}
}

