					bestScore, bestID = score, extTx.ID
				}
			}
			if bestScore >= 70 {
				usedExt[bestID] = true
				matched++
			} else {
				eid := "exc-" + intTx.ID
				exceptions[eid] = map[string]string{"type": "unmatched", "status": "open"}
				excCount++
			}
		}
		for _, extTx := range external {
			if !usedExt[extTx.ID] {
				eid := "exc-" + extTx.ID
				exceptions[eid] = map[string]string{"type": "unmatched", "status": "open"}
				excCount++
			}
		}
		return c.JSON(200, map[string]int{"matched_count": matched, "exception_count": excCount})
	})

	e.GET("/api/reconciliation/exceptions", func(c echo.Context) error {
		list := []map[string]string{}
		for id, exc := range exceptions {
			item := map[string]string{"id": id}
			for k, v := range exc {
				item[k] = v
			}
			list = append(list, item)
		}
		return c.JSON(200, list)
	})

	e.PUT("/api/reconciliation/exceptions/:id/resolve", func(c echo.Context) error {
		exc, ok := exceptions[c.Param("id")]
		if !ok {
			return c.JSON(404, map[string]string{"error": "not found"})
		}
		var req struct {
			Disposition string `json:"disposition"`
			Notes       string `json:"resolution_notes"`
		}
		if err := c.Bind(&req); err != nil {
			return c.JSON(400, map[string]string{"error": "bad request"})
		}
		if req.Disposition == "" {
			return c.JSON(400, map[string]string{"error": "disposition required"})
		}
		exc["status"] = "resolved"
		exc["disposition"] = req.Disposition
		return c.JSON(200, exc)
	})

	// Run matching
	matchReq := httptest.NewRequest(http.MethodPost, "/api/reconciliation/feeds/f1/match", nil)
	matchRec := httptest.NewRecorder()
	e.ServeHTTP(matchRec, matchReq)
	if matchRec.Code != 200 {
		t.Fatalf("match: %d", matchRec.Code)
	}
	var result map[string]int
	json.Unmarshal(matchRec.Body.Bytes(), &result)
	if result["matched_count"] < 1 {
		t.Error("expected at least 1 match (Acme Corp)")
	}
	if result["exception_count"] < 1 {
		t.Error("expected at least 1 exception (Delta Corp / Beta Inc unmatched)")
	}

	// List exceptions
	excReq := httptest.NewRequest(http.MethodGet, "/api/reconciliation/exceptions", nil)
	excRec := httptest.NewRecorder()
	e.ServeHTTP(excRec, excReq)
	if excRec.Code != 200 {
		t.Fatalf("list exceptions: %d", excRec.Code)
	}
	var excList []map[string]string
	json.Unmarshal(excRec.Body.Bytes(), &excList)
	if len(excList) == 0 {
		t.Fatal("expected exceptions")
	}

	// Resolve first exception
	resolveBody := `{"disposition":"write_off","resolution_notes":"Test resolution"}`
	resolveReq := httptest.NewRequest(http.MethodPut,
		"/api/reconciliation/exceptions/"+excList[0]["id"]+"/resolve",
		strings.NewReader(resolveBody))
	resolveReq.Header.Set("Content-Type", "application/json")
	resolveRec := httptest.NewRecorder()
	e.ServeHTTP(resolveRec, resolveReq)
	if resolveRec.Code != 200 {
		t.Errorf("resolve: %d", resolveRec.Code)
	}
	var resolved map[string]string
	json.Unmarshal(resolveRec.Body.Bytes(), &resolved)
	if resolved["status"] != "resolved" {
		t.Errorf("status=%s, want resolved", resolved["status"])
	}
}

func TestReconciliationWorkflow_ResolutionValidation(t *testing.T) {
