import re

with open('backend/cmd/main.go') as f:
    content = f.read()

# Parse route registrations
# Pattern: group.METHOD(path, handler)
# Need to track the group prefixes
lines = content.split('\n')

endpoints = []
current_prefix = ''

for line in lines:
    line = line.strip()

    # Track group definitions
    if 'e.Group(' in line or '.Group(' in line:
        m = re.search(r'\.Group\(\"([^\"]*?)\"', line)
        if m:
            prefix = m.group(1)
            # Figure out the variable name
            vm = re.match(r'(\w+)\s*:?=', line)

    # Track method registrations  
    for method in ['GET', 'POST', 'PUT', 'DELETE']:
        pattern = rf'\.{method}\(\"([^\"]*?)\"'
        m = re.search(pattern, line)
        if m:
            path = m.group(1)
            # Find the group variable
            gm = re.match(rf'(\w+)\.{method}', line)
            if gm:
                group = gm.group(1)
                endpoints.append((method, group, path))

# Map group variables to prefixes
groups = {}
for line in lines:
    line = line.strip()
    m = re.search(r'(\w+)\s*:?=\s*\w+\.Group\(\"([^\"]*?)\"', line)
    if m:
        groups[m.group(1)] = m.group(2)

# Build full paths
for method, group, path in endpoints:
    prefix = groups.get(group, '')
    full = prefix + path
    # Resolve nested groups
    if group == 'auth':
